import React, { useState, useRef } from 'react';
import {
  Container,
  Grid,
  Box,
  TextField,
  Button,
  Typography,
  Paper,
  useTheme,
  CircularProgress,
  Snackbar,
  Alert,
  Link
} from '@mui/material';
import {
  Email,
  Phone,
  GitHub,
  LinkedIn,
  Code,
  Send,
  AccessTime
} from '@mui/icons-material';

const ContactSection = () => {
  const theme = useTheme();
  const formRef = useRef(null);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: '',
    message: ''
  });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [snackbar, setSnackbar] = useState({
    open: false,
    message: '',
    severity: 'success'
  });

  // Form endpoint
  const FORM_ENDPOINT = "https://script.google.com/macros/s/AKfycbzIyALY5IW4Ov8JRnaopmKVxHXWTh98ZjpAFtu9cEF3UpUDmzphF7P4kQRFMl2MeHwS/exec";

  const contactInfo = [
    {
      icon: <Email sx={{ color: '#3ea8ff', fontSize: 24 }} />,
      title: 'Email',
      value: 'harsh160502@gmail.com',
      link: 'mailto:harsh160502@gmail.com'
    },
    {
      icon: <Phone sx={{ color: '#3ea8ff', fontSize: 24 }} />,
      title: 'Phone',
      value: '+91 9982346893',
      link: 'tel:+919982346893'
    },
    {
      icon: <GitHub sx={{ color: '#3ea8ff', fontSize: 24 }} />,
      title: 'GitHub',
      value: 'Harsh1652',
      link: 'https://github.com/Harsh1652'
    },
    {
      icon: <LinkedIn sx={{ color: '#3ea8ff', fontSize: 24 }} />,
      title: 'LinkedIn',
      value: 'harsh-gupta16',
      link: 'https://linkedin.com/in/harsh-gupta16'
    },
    {
      icon: <Code sx={{ color: '#3ea8ff', fontSize: 24 }} />,
      title: 'LeetCode',
      value: 'harsh160502',
      link: 'https://leetcode.com/harsh160502'
    }
  ];

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
    
    if (errors[name]) {
      setErrors({
        ...errors,
        [name]: ''
      });
    }
  };

  const validate = () => {
    const newErrors = {};
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!emailRegex.test(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    
    if (!formData.subject.trim()) {
      newErrors.subject = 'Subject is required';
    }
    
    if (!formData.message.trim()) {
      newErrors.message = 'Message is required';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleFormSubmit = async (e) => {
    e.preventDefault();
    
    if (!validate()) {
      return;
    }
    
    setLoading(true);
    
    try {
      const formDataToSend = new FormData();
      
      Object.entries(formData).forEach(([key, value]) => {
        formDataToSend.append(key, value);
      });
      
      formDataToSend.append('timestamp', new Date().toISOString());
      
      await fetch(FORM_ENDPOINT, {
        method: 'POST',
        mode: 'no-cors',
        body: formDataToSend,
      });
      
      setSnackbar({
        open: true,
        message: 'Message sent successfully! I will get back to you soon.',
        severity: 'success'
      });
      
      setFormData({
        name: '',
        email: '',
        subject: '',
        message: ''
      });
    } catch (error) {
      console.error('Error submitting form:', error);
      
      setSnackbar({
        open: true,
        message: 'Failed to send message. Please try again later.',
        severity: 'error'
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSnackbarClose = () => {
    setSnackbar({ ...snackbar, open: false });
  };

  // Custom text field style
  const inputProps = {
    sx: {
      bgcolor: 'rgba(30, 34, 45, 0.5)',
      borderRadius: 1,
      color: '#fff',
      '& .MuiOutlinedInput-notchedOutline': {
        borderColor: 'rgba(61, 167, 255, 0.2)',
      },
      '&:hover .MuiOutlinedInput-notchedOutline': {
        borderColor: 'rgba(61, 167, 255, 0.4)',
      },
      '&.Mui-focused .MuiOutlinedInput-notchedOutline': {
        borderColor: '#3ea8ff',
      },
      '& .MuiInputLabel-root': {
        color: 'rgba(255, 255, 255, 0.7)',
      },
      '& .MuiInputLabel-root.Mui-focused': {
        color: '#3ea8ff',
      }
    }
  };

  return (
    <Box
      id="contact"
      component="section"
      sx={{
        py: 8,
        backgroundColor: '#0d1117',
        position: 'relative',
        overflow: 'hidden',
        backgroundImage: 'radial-gradient(circle at 25% 25%, rgba(61, 167, 255, 0.05) 0%, transparent 50%), radial-gradient(circle at 75% 75%, rgba(61, 167, 255, 0.05) 0%, transparent 50%)',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundImage: 'url("data:image/svg+xml,%3Csvg width=\'100%25\' height=\'100%25\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cdefs%3E%3Cpattern id=\'grid\' width=\'40\' height=\'40\' patternUnits=\'userSpaceOnUse\'%3E%3Cpath d=\'M 40 0 L 0 0 0 40\' fill=\'none\' stroke=\'rgba(61, 167, 255, 0.05)\' stroke-width=\'0.5\'/%3E%3C/pattern%3E%3C/defs%3E%3Crect width=\'100%25\' height=\'100%25\' fill=\'url(%23grid)\'/%3E%3C/svg%3E")',
          opacity: 0.3,
          zIndex: -1,
        }
      }}
    >
      <Container maxWidth="lg">
        <Box textAlign="center" mb={5}>
          <Typography 
            variant="overline" 
            component="div" 
            sx={{ 
              color: '#3ea8ff', 
              fontWeight: 500, 
              letterSpacing: 2,
              mb: 1
            }}
          >
            GET IN TOUCH
          </Typography>
          <Typography 
            variant="h3" 
            component="h2" 
            fontWeight="600" 
            sx={{ 
              color: '#fff',
              mb: 2
            }}
          >
            Let's Work Together
          </Typography>
        </Box>

        <Grid container spacing={4} justifyContent="space-between">
          {/* Contact Form */}
          <Grid item xs={12} md={6}>
            <Box 
              p={4} 
              sx={{ 
                backgroundColor: 'rgba(15, 20, 30, 0.6)', 
                borderRadius: 2,
                border: '1px solid rgba(61, 167, 255, 0.1)',
                backdropFilter: 'blur(4px)',
                height: '100%',
              }}
            >
              <Typography 
                variant="h5" 
                component="h3"
                sx={{ 
                  color: '#fff', 
                  fontWeight: 500, 
                  mb: 3 
                }}
              >
                Send Me a Message
              </Typography>

              <Box 
                component="form" 
                ref={formRef}
                noValidate 
                onSubmit={handleFormSubmit}
              >
                <Grid container spacing={3}>
                  <Grid item xs={12} sm={6}>
                    <TextField
                      required
                      fullWidth
                      id="name"
                      name="name"
                      label="Your Name"
                      value={formData.name}
                      onChange={handleChange}
                      error={!!errors.name}
                      helperText={errors.name}
                      variant="outlined"
                      InputProps={inputProps}
                      InputLabelProps={{
                        sx: { color: 'rgba(255, 255, 255, 0.6)' }
                      }}
                      sx={{
                        '& .MuiFormHelperText-root': {
                          color: '#ff6b6b'
                        }
                      }}
                    />
                  </Grid>
                  <Grid item xs={12} sm={6}>
                    <TextField
                      required
                      fullWidth
                      id="email"
                      name="email"
                      label="Email Address"
                      value={formData.email}
                      onChange={handleChange}
                      error={!!errors.email}
                      helperText={errors.email}
                      variant="outlined"
                      InputProps={inputProps}
                      InputLabelProps={{
                        sx: { color: 'rgba(255, 255, 255, 0.6)' }
                      }}
                      sx={{
                        '& .MuiFormHelperText-root': {
                          color: '#ff6b6b'
                        }
                      }}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <TextField
                      required
                      fullWidth
                      id="subject"
                      name="subject"
                      label="Subject"
                      value={formData.subject}
                      onChange={handleChange}
                      error={!!errors.subject}
                      helperText={errors.subject}
                      variant="outlined"
                      InputProps={inputProps}
                      InputLabelProps={{
                        sx: { color: 'rgba(255, 255, 255, 0.6)' }
                      }}
                      sx={{
                        '& .MuiFormHelperText-root': {
                          color: '#ff6b6b'
                        }
                      }}
                    />
                  </Grid>
                  <Grid item xs={12}>
                    <TextField
                      required
                      fullWidth
                      id="message"
                      name="message"
                      label="Message"
                      multiline
                      rows={4}
                      value={formData.message}
                      onChange={handleChange}
                      error={!!errors.message}
                      helperText={errors.message}
                      variant="outlined"
                      InputProps={inputProps}
                      InputLabelProps={{
                        sx: { color: 'rgba(255, 255, 255, 0.6)' }
                      }}
                      sx={{
                        '& .MuiFormHelperText-root': {
                          color: '#ff6b6b'
                        }
                      }}
                    />
                  </Grid>
                </Grid>

                <Button
                  type="submit"
                  fullWidth
                  variant="contained"
                  disabled={loading}
                  sx={{
                    mt: 4,
                    py: 1.5,
                    backgroundColor: '#3ea8ff',
                    color: '#fff',
                    fontWeight: 600,
                    borderRadius: 1,
                    '&:hover': {
                      backgroundColor: '#2d8acc',
                      boxShadow: '0 4px 12px rgba(61, 167, 255, 0.3)'
                    }
                  }}
                >
                  {loading ? (
                    <CircularProgress size={24} color="inherit" />
                  ) : (
                    <>
                      Send Message
                      <Send sx={{ ml: 1, fontSize: 18 }} />
                    </>
                  )}
                </Button>
              </Box>
            </Box>
          </Grid>

          {/* Contact Information */}
          <Grid item xs={12} md={5}>
            <Box 
              p={4} 
              sx={{ 
                backgroundColor: 'rgba(15, 20, 30, 0.6)', 
                borderRadius: 2,
                border: '1px solid rgba(61, 167, 255, 0.1)',
                backdropFilter: 'blur(4px)',
                height: '100%',
                display: 'flex',
                flexDirection: 'column'
              }}
            >
              <Typography 
                variant="h5" 
                component="h3"
                sx={{ 
                  color: '#fff', 
                  fontWeight: 500, 
                  mb: 3 
                }}
              >
                Contact Information
              </Typography>
              
              <Typography variant="body1" sx={{ color: 'rgba(255, 255, 255, 0.8)', mb: 4 }}>
                Feel free to reach out through any of these channels. I'm always open to discussing
                new projects, creative ideas, or opportunities to be part of your vision.
              </Typography>
              
              <Box sx={{ mb: 4, flexGrow: 1 }}>
                {contactInfo.map((item, index) => (
                  <Box 
                    key={index}
                    sx={{ 
                      display: 'flex', 
                      alignItems: 'center', 
                      mb: 3,
                      p: 2,
                      borderRadius: 1,
                      backgroundColor: 'rgba(15, 20, 30, 0.5)',
                      transition: 'all 0.2s ease',
                      '&:hover': {
                        backgroundColor: 'rgba(61, 167, 255, 0.08)',
                        transform: 'translateX(5px)'
                      }
                    }}
                  >
                    <Box 
                      sx={{ 
                        mr: 2,
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center'
                      }}
                    >
                      {item.icon}
                    </Box>
                    <Box>
                      <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.6)', mb: 0.5 }}>
                        {item.title}
                      </Typography>
                      <Link
                        href={item.link}
                        target="_blank"
                        rel="noopener noreferrer"
                        sx={{
                          color: '#fff',
                          textDecoration: 'none',
                          fontWeight: 500,
                          '&:hover': {
                            color: '#3ea8ff',
                            textDecoration: 'none'
                          }
                        }}
                      >
                        {item.value}
                      </Link>
                    </Box>
                  </Box>
                ))}
              </Box>

              <Box 
                sx={{ 
                  p: 2.5, 
                  borderRadius: 1,
                  backgroundColor: 'rgba(61, 167, 255, 0.08)',
                  border: '1px solid rgba(61, 167, 255, 0.1)'
                }}
              >
                <Typography 
                  variant="subtitle1" 
                  sx={{ 
                    color: '#3ea8ff', 
                    fontWeight: 600, 
                    display: 'flex',
                    alignItems: 'center',
                    mb: 1
                  }}
                >
                  <AccessTime sx={{ mr: 1, fontSize: 20 }} />
                  Response Time
                </Typography>
                <Typography variant="body2" sx={{ color: 'rgba(255, 255, 255, 0.8)' }}>
                  I typically respond to messages within 24 hours. For urgent inquiries, please
                  contact me directly via phone.
                </Typography>
              </Box>
            </Box>
          </Grid>
        </Grid>
      </Container>

      <Snackbar
        open={snackbar.open}
        autoHideDuration={6000}
        onClose={handleSnackbarClose}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      >
        <Alert
          onClose={handleSnackbarClose}
          severity={snackbar.severity}
          sx={{
            width: '100%',
            backgroundColor: snackbar.severity === 'success' ? '#10b981' : '#ef4444',
            color: '#fff',
            '& .MuiAlert-icon': {
              color: '#fff'
            }
          }}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
};

export default ContactSection;
